const hasVoice = !!msg_obj.voice;
const hasVideo = !!msg_obj.video;
const hasMedia = hasPhoto || hasVoice || hasVideo;

if (hasMedia && !text) {
  const mediaType = hasPhoto ? 'photo' : hasVoice ? 'voice' : 'video';
  let fileId = '';
  if (hasPhoto) fileId = msg_obj.photo[msg_obj.photo.length - 1].file_id;
  else if (hasVoice) fileId = msg_obj.voice.file_id;
  else if (hasVideo) fileId = msg_obj.video.file_id;
  return [{ json: { action: 'ai', command: 'explain', query: 'Describe and explain what you see/hear', chatId, mediaType, fileId, respondAsAudio: hasVoice } }];
}

const cveMatch = text.match(/^\/cve\s+(CVE-\d{4}-\d{4,})/i);
if (cveMatch) return [{ json: { action: 'cve_lookup', cveId: cveMatch[1].toUpperCase(), chatId } }];

const searchMatch = text.match(/^\/search\s+(.+)/i);
if (searchMatch) return [{ json: { action: 'ai', command: 'search', query: searchMatch[1], chatId, respondAsAudio: false } }];

const explainMatch = text.match(/^\/explain\s+(.+)/i);
