  let fileId = '', mediaType = null;
  if (hasPhoto) { mediaType = 'photo'; fileId = msg_obj.photo[msg_obj.photo.length - 1].file_id; }
  else if (hasVoice) { mediaType = 'voice'; fileId = msg_obj.voice.file_id; }
