    category = r.category || 'all';
    chatId = r.chatId || defaultChatId;
    extended = r.extended || false;
    processingMsgId = r.processingMsgId || '';
  }
} catch(e) {
  // Cron path: these nodes didn't run, use defaults
}

if (!chatId) {
  console.log('❌ chatId is empty! For cron triggers, TELEGRAM_CHAT_ID env var is required.');
}

return items.map(i => ({
  json: {
    ...i.json,
    _requestedCategory: category,
    _chatId: chatId,
    _extended: extended,
    _processingMsgId: processingMsgId
