const defaultChatId = '';
const _d=s=>s?s.replace(/&amp;/g,String.fromCharCode(38)).replace(/&lt;/g,String.fromCharCode(60)).replace(/&gt;/g,String.fromCharCode(62)).replace(/&#(\d+);/g,(m,c)=>String.fromCharCode(c)).replace(/&quot;/g,String.fromCharCode(34)).replace(/&apos;/g,String.fromCharCode(39)).replace(/&#x([0-9a-f]+);/gi,(m,c)=>String.fromCharCode(parseInt(c,16))):s;
const _esc=s=>s?s.replace(/&/g,'&amp;').replace(/"/g,'&quot;').replace(/</g,'&lt;').replace(/>/g,'&gt;'):s;
const _dom=l=>{try{const h=new URL(l).hostname.replace(/^www\./,'');const p=h.split('.');return p.length>=2?p.slice(-2).join('.'):h;}catch(e){return null;}};
const _join=d=>{if(d.length===1)return d[0];if(d.length===2)return d[0]+' and '+d[1];return d.slice(0,-1).join(', ')+', and '+d[d.length-1];};
const _svcLines=(svcItems,html)=>{
  const map=new Map(),nonMatch=[];
  for(const i of svcItems){
    const m=_d(i.json.title||'').match(/^(.+?)\s+on\s+(\d{4}-\d{2}-\d{2})/);
    if(m){const loc=m[1].trim(),date=m[2];if(!map.has(loc))map.set(loc,[]);map.get(loc).push({date,link:i.json.link,source:i.json.source||_dom(i.json.link)});}
    else nonMatch.push(i);
  }
  const tgt=html?' target="_blank"':'';
  const lines=[];
  for(const[loc,entries]of map){
    entries.sort((a,b)=>b.date.localeCompare(a.date));
    const src=entries[0]?.source?` <i>(${entries[0].source})</i>`:'';
    const dl=entries.map(e=>`<a${tgt} href="${_esc(e.link)}">${e.date}</a>`);
    lines.push(`• ${html?_esc(loc):loc}${src} on ${_join(dl)}`);
  }
  for(const i of nonMatch){
    const src=i.json.source||_dom(i.json.link);
    const srcTxt=src?` <i>(${src})</i>`:'';
    lines.push(`• <a${tgt} href="${_esc(i.json.link)}">${html?_esc(_d(i.json.title)):_d(i.json.title)}</a>${srcTxt}`);
  }
  return lines;
};

const sections = {
  cve:{emoji:'🛡️',title:'CVE Alerts',limit:0},
  security_news:{emoji:'🔐',title:'Security News',limit:0},
  service:{emoji:'⚠️',title:'Service Disruptions',limit:0},
  retrogaming:{emoji:'🎮',title:'Retrogaming/Modding',limit:5},
  scitech:{emoji:'🔬',title:'Science & Tech',limit:5},
  world:{emoji:'🌍',title:'World News',limit:5},
  hackernews:{emoji:'🟠',title:'Hacker News',limit:5},
  brpt:{emoji:'🇧🇷🇵🇹',title:'Brazil & Portugal',limit:6,balanced:true},
  youtube:{emoji:'📺',title:'YouTube',limit:0}
};

const reqCat=items[0]?.json?._requestedCategory||'all';
const chatId=items[0]?.json?._chatId||defaultChatId;
const extended=items[0]?.json?._extended||false;
const processingMsgId=items[0]?.json?._processingMsgId||'';
const dateStr=new Date().toLocaleDateString('en-GB',{weekday:'short',month:'short',day:'numeric'});

const sectionData=[],emptyCategories=[];
for(const [key,sec] of Object.entries(sections)){
  if(reqCat!=='all'&&reqCat!==key)continue;
  const group=items.filter(i=>i.json.type===key);
  if(!group.length){emptyCategories.push(`  - ${sec.emoji} ${sec.title}`);continue;}
  const maxItems=(!extended&&sec.limit>0)?sec.limit:group.length;
  let shown;
  if(!extended && sec.balanced){
    const br=group.filter(i=>i.json.country==='br').slice(0,3);
    const pt=group.filter(i=>i.json.country==='pt').slice(0,3);
    shown=[...br,...pt];
    if(shown.length===0)shown=group.slice(0,maxItems);
  } else {
    shown=group.slice(0,maxItems);
  }
  const remaining=group.length-shown.length;
  const cmd=key==='hackernews'?'hn':key;
  sectionData.push({key,emoji:sec.emoji,title:sec.title,items:shown,remaining,cmd,total:group.length});
}

const aiBriefing=items[0]?.json?._aiBriefing||null;const storyOfDay=items[0]?.json?._storyOfTheDay||null;const textLines=[];if(storyOfDay)textLines.push(storyOfDay,'');if(aiBriefing)textLines.push(aiBriefing,'─────────────────','');textLines.push(`📰 News Clipper — ${dateStr}`,'');
for(const s of sectionData){
  textLines.push(`${s.emoji} ${s.title}`);
  if(s.key==='service'){
    textLines.push(..._svcLines(s.items,false));
  } else if(s.key==='brpt'){
    const _brItems=s.items.filter(i=>i.json.country!=='pt');
    const _ptItems=s.items.filter(i=>i.json.country==='pt');
    const _tSubs=_brItems.length<=_ptItems.length?[{items:_brItems,hdr:'  🇧🇷 Brasil'},{items:_ptItems,hdr:'  🇵🇹 Portugal'}]:[{items:_ptItems,hdr:'  🇵🇹 Portugal'},{items:_brItems,hdr:'  🇧🇷 Brasil'}];
    for(const sub of _tSubs){if(!sub.items.length)continue;textLines.push(sub.hdr);for(const i of sub.items){const _da=(i.json.duplicates||[]).map(d=>`<a href="${_esc(d.link)}">${d.source||'src'}</a>`).join(', ');const _also=_da?` [${_da}]`:'';textLines.push(`• <a href="${_esc(i.json.link)}">${_d(i.json.title)}</a>${_also}`);}}
  } else {
    for(const i of s.items){
      const score=i.json.score?` [${i.json.score}]`:'';
      const flag=i.json.country==='br'?'🇧🇷 ':i.json.country==='pt'?'🇵🇹 ':'';
      textLines.push(`• ${flag}<a href="${_esc(i.json.link)}">${_d(i.json.title)}${score}</a>`);
    }
  }
  if(s.remaining>0)textLines.push(`  ⤷ +${s.remaining} more → /${s.cmd} extended`);
  textLines.push('');
}
if(emptyCategories.length){textLines.push('📭 No updates today:');textLines.push(...emptyCategories);}
const textMsg=textLines.join('\n');

if(textMsg.length<=4000){
  return[{json:{mode:'text',text:textMsg,chatId,processingMsgId}}];
}

// HTML file mode
const allSections=[],allEmpty=[];
for(const[key,sec]of Object.entries(sections)){
  if(reqCat!=='all'&&reqCat!==key)continue;
  const group=items.filter(i=>i.json.type===key);
  if(!group.length){allEmpty.push(`  - ${sec.emoji} ${sec.title}`);continue;}
  allSections.push({key,emoji:sec.emoji,title:sec.title,items:group});
}

allSections.sort((a,b)=>a.items.length-b.items.length);
let sh='';
for(const s of allSections){
  let _sHtml='';
  if(s.key==='service'){
    let li='';for(const line of _svcLines(s.items,true))li+=`<li>${line}</li>`;
    _sHtml=`<div class="section"><h2>${s.emoji} ${s.title} <span class="count">(${s.items.length})</span></h2><ul>${li}</ul></div>\n`;
  } else if(s.key==='brpt'){
    const _brI=s.items.filter(i=>i.json.country!=='pt'),_ptI=s.items.filter(i=>i.json.country==='pt');
    const _subs=_brI.length<=_ptI.length?[{items:_brI,flag:'🇧🇷',label:'Brasil'},{items:_ptI,flag:'🇵🇹',label:'Portugal'}]:[{items:_ptI,flag:'🇵🇹',label:'Portugal'},{items:_brI,flag:'🇧🇷',label:'Brasil'}];
    let inner='';
    for(const sub of _subs){if(!sub.items.length)continue;inner+=`<h3 class="subsec">${sub.flag} ${sub.label} <span class="count">(${sub.items.length})</span></h3><ul>`;for(const i of sub.items){const t=_esc(_d(i.json.title));const dupes=i.json.duplicates||[];const pills=dupes.length>0?`<span class="srcs">${dupes.map(d=>`<a href="${_esc(d.link)}" target="_blank">${_esc(d.source||'src')}</a>`).join('')}</span>`:'';inner+=`<li><a href="${_esc(i.json.link)}" target="_blank">${t}</a>${pills}</li>`;}inner+='</ul>';}
    _sHtml=`<div class="section"><h2>${s.emoji} ${s.title} <span class="count">(${s.items.length})</span></h2>${inner}</div>\n`;
  } else {
    let li='';for(const i of s.items){const t=_esc(_d(i.json.title));const sc=i.json.score?`<span class="score">[CVSS: ${i.json.score}]</span>`:'';li+=`<li><a href="${_esc(i.json.link)}" target="_blank">${t}</a> ${sc}</li>`;}
    _sHtml=`<div class="section"><h2>${s.emoji} ${s.title} <span class="count">(${s.items.length})</span></h2><ul>${li}</ul></div>\n`;
  }
