    }

    if (_filePath) {
      const _tgUrl = `https://api.telegram.org/file/bot${_tToken}/${_filePath}`;

      // Step 2: download binary once — reused by both providers
      let _audioBuf = null;
      try {
        const _raw = await this.helpers.httpRequest({
          method: 'GET', url: _tgUrl, encoding: 'arraybuffer',
        });
        _audioBuf = Buffer.isBuffer(_raw) ? _raw : Buffer.from(_raw);
        console.log(`Audio: ${_audioBuf.length}B magic:${_audioBuf.slice(0,4).toString('hex')}`);
      } catch (_e) {
