      }

      if (_audioBuf) {
        // Gemini multi-model fallback (each model has separate rate limits: 15 RPM / 1500 RPD)
        // Then Groq Whisper as last resort
        if (_gKey && !_transcribed) {
          const _b64 = _audioBuf.toString('base64');
          const _models = ['gemini-2.0-flash', 'gemini-2.5-flash', 'gemini-2.0-flash-lite'];
          for (const _model of _models) {
            if (_transcribed) break;
