        // Last resort: Groq Whisper (manual multipart — n8n httpRequest formData is broken)
        if (_groqKey && !_transcribed && _audioBuf) {
          try {
            const _bd = 'n8n' + Date.now().toString(36);
            const _mp = Buffer.concat([
              Buffer.from('--' + _bd + '\r\nContent-Disposition: form-data; name="model"\r\n\r\nwhisper-large-v3-turbo\r\n'),
