            if (_grd?.error) throw new Error(_grd.error.message || JSON.stringify(_grd.error));
            const _t = _grd?.text?.trim();
            if (_t) { query = _t; _transcribed = true; console.log(`Groq transcribed: "${_t}"`); }
            else _errors.push(`Groq(${_audioBuf.length}B): ${JSON.stringify(_grd).substring(0, 100)}`);
          } catch (_e) { _errors.push(`Groq: ${(_e?.message || String(_e)).substring(0, 120)}`); }
        }
      }
    }
  }

  // Voice input → voice output
    respondAsAudio = true;

    if (!_transcribed) {
