const items = $input.all();
const results = [];

for (const item of items) {
  const url = item.json.url;
  const source = item.json.source || '';

  try {
    // Fetch raw response as arraybuffer to handle encoding properly
    const response = await this.helpers.httpRequest({
      method: 'GET',
      url: url,
      encoding: 'arraybuffer',
      timeout: 15000,
      headers: {
        'User-Agent': 'Mozilla/5.0 (compatible; n8n RSS Reader)',
        'Accept': 'application/rss+xml, application/xml, text/xml, */*',
      },
    });

    // Convert buffer to string, trying to detect encoding
    let xmlStr;
    if (response instanceof Buffer || response?.type === 'Buffer') {
      const buf = Buffer.isBuffer(response) ? response : Buffer.from(response.data || response);

      // Check XML declaration for encoding
      const head = buf.slice(0, 200).toString('ascii');
      const encMatch = head.match(/encoding=["']([^"']+)["']/i);
      const declaredEnc = encMatch ? encMatch[1].toLowerCase() : 'utf-8';

      if (declaredEnc.includes('iso-8859') || declaredEnc.includes('latin') || declaredEnc.includes('windows-1252')) {
        // Declared Latin-1 family: decode directly
        xmlStr = buf.toString('latin1');
      } else {
        // Declared UTF-8 (or unknown): try UTF-8, but some feeds lie —
        // if replacement chars appear, the bytes are actually Latin-1
        xmlStr = buf.toString('utf-8');
        if (xmlStr.includes('\uFFFD')) {
          xmlStr = buf.toString('latin1');
        }
      }
    } else if (typeof response === 'string') {
      xmlStr = response;
    } else {
      xmlStr = JSON.stringify(response);
    }

    // Parse titles and links from XML using regex (works for RSS and Atom)
    // Skip the first <title> (channel title)
    const itemBlocks = xmlStr.split(/<item[\s>]/i).slice(1);
    // Also handle Atom <entry> format
    const entryBlocks = xmlStr.split(/<entry[\s>]/i).slice(1);
    const blocks = itemBlocks.length > 0 ? itemBlocks : entryBlocks;

    for (const block of blocks) {
      const titleMatch = block.match(/<title[^>]*>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/title>/is);
      const linkMatch = block.match(/<link[^>]*>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/link>/is) 
                      || block.match(/<link[^>]*href=["']([^"']+)["']/i);

      if (titleMatch) {
        let title = titleMatch[1].trim();
        // Decode HTML entities
        title = title
          .replace(/&amp;/g, '&')
          .replace(/&lt;/g, '<')
          .replace(/&gt;/g, '>')
          .replace(/&quot;/g, '"')
          .replace(/&apos;/g, "'")
          .replace(/&#(\d+);/g, (m, c) => String.fromCharCode(parseInt(c)))
          .replace(/&#x([0-9a-f]+);/gi, (m, c) => String.fromCharCode(parseInt(c, 16)));

        const link = linkMatch ? (linkMatch[1] || linkMatch[2] || '').trim() : '';

        results.push({
          json: {
            title: title,
            link: link,
            source: source,
          }
        });
      }
    }
  } catch (err) {
    console.log(`⚠️ Failed to fetch ${url}: ${err.message}`);
  }
}

console.log(`🇧🇷🇵🇹 Fetched ${results.length} items from ${items.length} feeds`);
