const items = $input.all();
const brptItems = items.filter(i => i.json.type === 'brpt');
if (brptItems.length < 2) return items;

const geminiKey = $env.GEMINI_API_KEY ?? $env.N8N_GEMINI_API_KEY ?? '';
const cerebrasKey = $env.N8N_CEREBRAS_API_KEY ?? $env.CEREBRAS_API_KEY ?? '';
const mistralKey = $env.N8N_MISTRAL_API_KEY ?? $env.MISTRAL_API_KEY ?? '';
if (!geminiKey && !cerebrasKey && !mistralKey) {
  console.log('⚠️ No AI key available, skipping BRPT deduplication');
  return items;
}

const itemList = brptItems.map((item, idx) => ({
  id: idx,
  title: item.json.title,
  source: item.json.source || '',
  country: item.json.country || 'br',
}));

const prompt = `You are a news deduplication assistant. Given news items from Brazilian and Portuguese news sources, identify which items cover the EXACT same news event (different sources reporting the same story).

Rules:
- Only group items that report the SAME specific event
- Articles merely on the same broad topic (e.g. "Iran") but covering different angles are NOT duplicates
- Each group should have the most detailed/primary source first
- Singletons (no duplicates) get their own group

News items:
${itemList.map(i => '[' + i.id + '] (' + i.source + '/' + i.country + '): ' + i.title).join('\n')}

Respond ONLY with valid JSON: {"groups": [[0,2,5], [1], [3,4], ...]}`;

let groups = null;
try {
  const resp = await this.helpers.httpRequest({
    method: 'POST',
    url: `https://generativelanguage.googleapis.com/v1/models/gemini-2.0-flash:generateContent?key=${geminiKey}`,
    body: {
      contents: [{ role: 'user', parts: [{ text: prompt }] }],
      generationConfig: { maxOutputTokens: 2048, temperature: 0.1, responseMimeType: 'application/json' }
    },
    json: true,
    timeout: 25000,
  });
  const raw = resp.candidates?.[0]?.content?.parts?.[0]?.text || '';
  const parsed = JSON.parse(raw);
  if (Array.isArray(parsed.groups)) {
    groups = parsed.groups;
    console.log(`✅ BRPT dedup: ${brptItems.length} items → ${groups.length} groups`);
  }
} catch (e) {
  console.log(`⚠️ BRPT dedup failed: ${e.message?.substring(0, 120)}`);
}

if (!groups && cerebrasKey) {
  try {
    const resp = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.cerebras.ai/v1/chat/completions',
      headers: { Authorization: `Bearer ${cerebrasKey}` },
      body: {
        model: 'llama-3.3-70b',
        messages: [{ role: 'user', content: prompt }],
        max_tokens: 2048, temperature: 0.1
      },
      json: true, timeout: 25000,
    });
    const raw = resp.choices?.[0]?.message?.content || '';
    const jsonStr = raw.replace(/^```json\s*/i, '').replace(/```\s*$/, '').trim();
    const parsed = JSON.parse(jsonStr);
    if (Array.isArray(parsed.groups)) {
      groups = parsed.groups;
      console.log(`✅ BRPT dedup via Cerebras: ${brptItems.length} items → ${groups.length} groups`);
    }
  } catch (e) {
    console.log(`⚠️ BRPT dedup Cerebras failed: ${e.message?.substring(0, 120)}`);
  }
}
if (!groups && mistralKey) {
  try {
    const resp = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.mistral.ai/v1/chat/completions',
      headers: { Authorization: `Bearer ${mistralKey}` },
      body: {
        model: 'mistral-small-latest',
        messages: [{ role: 'user', content: prompt }],
        max_tokens: 2048, temperature: 0.1, response_format: { type: 'json_object' }
      },
      json: true, timeout: 25000,
    });
    const raw = resp.choices?.[0]?.message?.content || '';
    const jsonStr = raw.replace(/^```json\s*/i, '').replace(/```\s*$/, '').trim();
    const parsed = JSON.parse(jsonStr);
    if (Array.isArray(parsed.groups)) {
      groups = parsed.groups;
      console.log(`✅ BRPT dedup via Mistral: ${brptItems.length} items → ${groups.length} groups`);
    }
  } catch (e) {
    console.log(`⚠️ BRPT dedup Mistral failed: ${e.message?.substring(0, 120)}`);
  }
}
if (!groups) return items;

// Sanitise AI output: remove out-of-range indices, drop empty groups
groups = groups
  .map(g => g.filter(id => Number.isInteger(id) && id >= 0 && id < brptItems.length))
  .filter(g => g.length > 0);

// Ensure every index appears (add missing as singletons)
const seen = new Set(groups.flat());
for (let i = 0; i < brptItems.length; i++) {
  if (!seen.has(i)) groups.push([i]);
}

const processedBrpt = groups.map(group => {
  const canonical = brptItems[group[0]].json;
  const dupes = group.slice(1).map(id => ({
    title: brptItems[id].json.title,
    link: brptItems[id].json.link,
    source: brptItems[id].json.source || '',
    country: brptItems[id].json.country || 'br',
  }));
  return {
    json: {
      ...canonical,
      duplicates: dupes.length > 0 ? dupes : undefined,
    }
  };
});

return [...items.filter(i => i.json.type !== 'brpt'), ...processedBrpt];
